// COMPLETE, COMPILABLE C code
#include <stdio.h>
#include <stdlib.h>
#define MAX_N 100005

// Define the structure for a tree node
typedef struct Node {
    int value;
    struct Node** children;
    int numChildren;
} Node;

// Function to create a new node
Node* createNode(int value) {
    Node* node = (Node*) malloc(sizeof(Node));
    node->value = value;
    node->children = NULL;
    node->numChildren = 0;
    return node;
}

// Function to add a child to a node
void addChild(Node* node, Node* child) {
    node->numChildren++;
    node->children = (Node**) realloc(node->children, node->numChildren * sizeof(Node*));
    node->children[node->numChildren - 1] = child;
}

// Function to calculate the size of a subtree
int calculateSubtreeSize(Node* node) {
    int size = 1;
    for (int i = 0; i < node->numChildren; i++) {
        size += calculateSubtreeSize(node->children[i]);
    }
    return size;
}

// Function to calculate the cost of a path
int calculatePathCost(Node* node, int depth) {
    int cost = 0;
    if (node->numChildren == 0) {
        return depth;
    }
    for (int i = 0; i < node->numChildren; i++) {
        cost += calculatePathCost(node->children[i], depth + 1);
    }
    return cost;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        int N;
        scanf("%d", &N);
        Node* root = createNode(1);
        for (int i = 0; i < N - 1; i++) {
            int a, b;
            scanf("%d %d", &a, &b);
            Node* nodeA = createNode(a);
            Node* nodeB = createNode(b);
            addChild(nodeA, nodeB);
        }
        int subtreeSize = calculateSubtreeSize(root);
        int pathCost = calculatePathCost(root, 0);
        printf("%d\n", pathCost);
    }
    return 0;
}

