// COMPLETE, COMPILABLE Java code
import java.util.ArrayList;
import java.util.Scanner;

public class Main {
    // Define the structure for a tree node
    static class Node {
        int value;
        ArrayList<Node> children;

        public Node(int value) {
            this.value = value;
            this.children = new ArrayList<>();
        }
    }

    // Function to add a child to a node
    public static void addChild(Node node, Node child) {
        node.children.add(child);
    }

    // Function to calculate the size of a subtree
    public static int calculateSubtreeSize(Node node) {
        int size = 1;
        for (Node child : node.children) {
            size += calculateSubtreeSize(child);
        }
        return size;
    }

    // Function to calculate the cost of a path
    public static int calculatePathCost(Node node, int depth) {
        int cost = 0;
        if (node.children.isEmpty()) {
            return depth;
        }
        for (Node child : node.children) {
            cost += calculatePathCost(child, depth + 1);
        }
        return cost;
    }

    public static void main(String[] args) {
        Scanner scanner = new Scanner(System.in);
        int T = scanner.nextInt();
        for (int t = 0; t < T; t++) {
            int N = scanner.nextInt();
            Node root = new Node(1);
            for (int i = 0; i < N - 1; i++) {
                int a = scanner.nextInt();
                int b = scanner.nextInt();
                Node nodeA = new Node(a);
                Node nodeB = new Node(b);
                addChild(nodeA, nodeB);
            }
            int subtreeSize = calculateSubtreeSize(root);
            int pathCost = calculatePathCost(root, 0);
            System.out.println(pathCost);
        }
    }
}

